with:
  def _clean(obj: str) -> str:
              obj = obj.strip()
              # Strip surrounding double quotes
              if obj.startswith('"') and obj.endswith('"'):
                  obj = obj[1:-1]
              # Separate numeric value from unit if present in parentheses
              if " (" in obj and obj.endswith(")"):
                  main, unit = obj.split(" (", 1)
                  unit = unit.rstrip(")")
                  # Clean numeric part: drop trailing .0 for integers
                  try:
                      num = float(main)
                      if num.is_integer():
                          main = str(int(num))
                      else:
                          main = str(num)
                  except ValueError:
                      pass
                  obj = f"{main} {unit}"
              else:
                  # Clean numeric part without explicit unit
                  try:
                      num = float(obj)
                      if num.is_integer():
                          obj = str(int(num))
                      else:
                          obj = str(num)
                  except ValueError:
                      pass
              return obj
